import{_ as a,c as e,o,a as i}from"./app.dd797cc2.js";const f=JSON.parse('{"title":"Introdução","description":"","frontmatter":{"title":"Introdução","editLink":false,"slug":false},"headers":[{"level":2,"title":"Atualização","slug":"atualizacao","link":"#atualizacao","children":[]}],"relativePath":"introducao.md"}'),t={name:"introducao.md"},d=i('<h1 id="introducao" tabindex="-1">Introdução <a class="header-anchor" href="#introducao" aria-hidden="true">#</a></h1><p>Os dados serão enviados ao portal Chaves na Mão via arquivo XML. O cliente deverá disponibilizar uma URL na internet para que seja efetuada a leitura e/ou download deste arquivo. O arquivo deverá ficar disponível para acesso a qualquer momento, onde o portal poderá baixar as informações e atualizar os dados no sistema do portal.<br></p><p>De preferência, o XML gerado pelo sistema do cliente deverá ser dinâmico, sendo atualizado automaticamente com os imóveis contido no sistema do cliente. A leitura desse arquivo é realizada 1 (uma) vez por dia, podendo ser durante o dia ou a noite, dependendo da fila de execução de cada integração.</p><h2 id="atualizacao" tabindex="-1">Atualização <a class="header-anchor" href="#atualizacao" aria-hidden="true">#</a></h2><p>A data de atualização do anúncio é obrigatória. Apenas os anúncios com data de atualização posterior à data da última execução serão atualizados.</p><p>Após o imóvel ser indexado pela primeira vez, as fotos serão atualizadas quando:</p><ul><li>A data de atualização do anúncio for posterior à data da última atualização e a URL da imagem for alterada;</li><li>Ou quando a data de alteração da imagem for posterior à data da última atualização.</li></ul>',7),r=[d];function n(s,l,u,c,p,m){return o(),e("div",null,r)}const h=a(t,[["render",n]]);export{f as __pageData,h as default};
